settings.custom_liquid:
{%- assign lume_uid = section.id | default: product.id -%}
{%- assign current_variant = product.selected_or_first_available_variant -%}
{%- assign pick_up_availabilities = current_variant.store_availabilities | where: 'pick_up_enabled', true -%}

<div class="lume-fulfilment" id="lume-fulfilment-{{ lume_uid }}">

  <!-- DELIVERY -->
  <div class="lume-row">
    <div class="lume-label">Shipping</div>

    <div class="lume-body">
      <div class="lume-primary">
        <span id="ship-title-{{ lume_uid }}">Ships Today</span>
      </div>

      <div class="lume-secondary">
        <span id="ship-sub-{{ lume_uid }}">Order within the next</span>
        <span class="lume-timer" id="ship-timer-{{ lume_uid }}"></span>
      </div>
    </div>

    <div class="lume-meta"></div>
  </div>

  <!-- IN STORE -->
  <div class="lume-row">
    <div class="lume-label">Pickup</div>

    <div class="lume-body">
      <pickup-availability
        class="product__pickup-availabilities lume-pickup"
        {% if current_variant.available and pick_up_availabilities.size > 0 %}available{% endif %}
        data-root-url="{{ routes.root_url }}"
        data-variant-id="{{ current_variant.id }}"
        data-has-only-default-variant="{{ product.has_only_default_variant }}"
      >
        <template>
          <pickup-availability-preview class="pickup-availability-preview">
            <span class="svg-wrapper">{{- 'icon-unavailable.svg' | inline_asset_content -}}</span>
            <div class="pickup-availability-info">
              <p class="caption-large">{{ 'products.pickup_availability.unavailable' | t }}</p>
              <button class="pickup-availability-button">
                {{ 'products.pickup_availability.refresh' | t }}
              </button>
            </div>
          </pickup-availability-preview>
        </template>
      </pickup-availability>
    </div>

    <div class="lume-meta"></div>
  </div>

</div>

<script>
(function(){
  if (window.__lumePickupLoaded) return;
  window.__lumePickupLoaded = true;
  var s = document.createElement('script');
  s.src = "{{ 'pickup-availability.js' | asset_url }}";
  s.defer = true;
  document.head.appendChild(s);
})();
</script>

<style>
/* ================= CONTAINER ================= */
#lume-fulfilment-{{ lume_uid }}{
  margin-top: 14px;
}

/* ================= ROW ================= */
#lume-fulfilment-{{ lume_uid }} .lume-row{
  display:grid;
  grid-template-columns: 82px 1fr;
  gap:12px;
  padding:12px 0;
  align-items:start;
}

/* ================= TYPOGRAPHY ================= */
#lume-fulfilment-{{ lume_uid }} .lume-label{
  font-size:11px;
  font-weight:600;
  color:#222222;
  letter-spacing:0.6px;
  text-transform:none;
  line-height:1.2;
  margin-top:2px;
}

#lume-fulfilment-{{ lume_uid }} .lume-primary{
  font-size:13px;
  font-weight:600;
  color:#222222;
  line-height:1.35;
}

#lume-fulfilment-{{ lume_uid }} .lume-secondary{
  margin-top:4px;
  font-size:12px;
  font-weight:400;
  color:#222222;
  line-height:1.35;
  display:flex;
  flex-wrap:wrap;
  gap:6px;
  align-items:baseline;
}

#lume-fulfilment-{{ lume_uid }} .lume-timer strong{
  font-weight:500;
  font-size:12px;
  color:#222222;
}

/* ================= PICKUP HARD RESET ================= */
#lume-fulfilment-{{ lume_uid }} .lume-pickup{
  background:transparent !important;
  border:0 !important;
  padding:0 !important;
  margin:0 !important;
  box-shadow:none !important;
}

#lume-fulfilment-{{ lume_uid }} pickup-availability .svg-wrapper{
  display:none !important;
}
#lume-fulfilment-{{ lume_uid }} pickup-availability .pickup-availability-preview{
  padding:0 !important;
  margin:0 !important;
}
#lume-fulfilment-{{ lume_uid }} pickup-availability .pickup-availability-info{
  margin:0 !important;
}
#lume-fulfilment-{{ lume_uid }} pickup-availability .pickup-availability-info p{
  font-size:13px;
  font-weight:600;
  color:#222222;
  margin:0 !important;
}

#lume-fulfilment-{{ lume_uid }} pickup-availability .pickup-availability-button{
  margin-top:4px;
  font-size:12px;
  font-weight:400;
  color:#222222;
  background:none !important;
  border:0 !important;
  padding:0 !important;
  cursor:pointer;
  text-decoration:none;
  position:relative;
}

#lume-fulfilment-{{ lume_uid }} pickup-availability .pickup-availability-button::after{
  content:"";
  position:absolute;
  left:0;
  bottom:-2px;
  width:100%;
  height:1px;
  background:currentColor;
  opacity:.35;
}

#lume-fulfilment-{{ lume_uid }} pickup-availability .pickup-availability-button:hover{
  color:#222222;
}
#lume-fulfilment-{{ lume_uid }} pickup-availability .pickup-availability-button:hover::after{
  opacity:.6;
}

/* ================= MOBILE ================= */
@media (max-width: 749px){
  #lume-fulfilment-{{ lume_uid }} .lume-row{
    grid-template-columns:1fr;
    gap:6px;
    padding:12px 0;
  }
  #lume-fulfilment-{{ lume_uid }} .lume-label{
    font-size:10px;
    margin-top:0;
  }
}
</style>

<script>
(function(){
  const uid = "{{ lume_uid }}";
  const titleEl = document.getElementById("ship-title-" + uid);
  const subEl = document.getElementById("ship-sub-" + uid);
  const timerEl = document.getElementById("ship-timer-" + uid);
  if (!titleEl || !subEl || !timerEl) return;

  /* =========================
        TEST MODE
     =========================
     enabled: false -> uses real Brisbane time
     enabled: true  -> uses values below as Brisbane local time

     month: 1-12
     hour:  0-23
  */
  const TEST_MODE = {
    enabled: false,

    year: 2026,
    month: 2,
    day: 25,
    hour: 14,
    minute: 0,
    second: 0
  };

  const cutoffHour = 14;
  const cutoffMinute = 30;
  const timeZone = "Australia/Brisbane";
  const weekdayToIndex = { Sun: 0, Mon: 1, Tue: 2, Wed: 3, Thu: 4, Fri: 5, Sat: 6 };
  const weekdayNames = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
  const holidayCache = new Map();

  function getReferenceDate() {
    if (TEST_MODE.enabled) {
      return new Date(
        TEST_MODE.year,
        TEST_MODE.month - 1,
        TEST_MODE.day,
        TEST_MODE.hour,
        TEST_MODE.minute,
        TEST_MODE.second
      );
    }
    return new Date();
  }

  function getBrisbaneParts(date) {
    const parts = new Intl.DateTimeFormat("en-AU", {
      timeZone,
      weekday: "short",
      year: "numeric",
      month: "2-digit",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit",
      hourCycle: "h23"
    }).formatToParts(date);

    const map = {};
    parts.forEach(function(part) {
      if (part.type !== "literal") map[part.type] = part.value;
    });

    return {
      year: Number(map.year),
      month: Number(map.month),
      day: Number(map.day),
      hour: Number(map.hour),
      minute: Number(map.minute),
      second: Number(map.second),
      weekday: weekdayToIndex[map.weekday]
    };
  }

  function toLocalDate(parts) {
    return new Date(
      parts.year,
      parts.month - 1,
      parts.day,
      parts.hour || 0,
      parts.minute || 0,
      parts.second || 0,
      0
    );
  }

  function atStartOfDay(date) {
    return new Date(date.getFullYear(), date.getMonth(), date.getDate());
  }

  function addDays(date, days) {
    const next = new Date(date);
    next.setDate(next.getDate() + days);
    return next;
  }

  function formatDateKey(date) {
    const yyyy = date.getFullYear();
    const mm = String(date.getMonth() + 1).padStart(2, "0");
    const dd = String(date.getDate()).padStart(2, "0");
    return yyyy + "-" + mm + "-" + dd;
  }

  function sameDate(a, b) {
    return formatDateKey(a) === formatDateKey(b);
  }

  function nthWeekdayOfMonth(year, month, weekday, occurrence) {
    const first = new Date(year, month - 1, 1);
    const offset = (weekday - first.getDay() + 7) % 7;
    return new Date(year, month - 1, 1 + offset + ((occurrence - 1) * 7));
  }

  function getEasterSunday(year) {
    const a = year % 19;
    const b = Math.floor(year / 100);
    const c = year % 100;
    const d = Math.floor(b / 4);
    const e = b % 4;
    const f = Math.floor((b + 8) / 25);
    const g = Math.floor((b - f + 1) / 3);
    const h = (19 * a + b - d - g + 15) % 30;
    const i = Math.floor(c / 4);
    const k = c % 4;
    const l = (32 + (2 * e) + (2 * i) - h - k) % 7;
    const m = Math.floor((a + (11 * h) + (22 * l)) / 451);
    const month = Math.floor((h + l - (7 * m) + 114) / 31);
    const day = ((h + l - (7 * m) + 114) % 31) + 1;
    return new Date(year, month - 1, day);
  }

  function getBrisbaneShowDay(year) {
    let showStart = nthWeekdayOfMonth(year, 8, 5, 1);
    if (showStart.getDate() < 5) {
      showStart = nthWeekdayOfMonth(year, 8, 5, 2);
    }
    return addDays(showStart, 5);
  }

  function buildQueenslandPublicHolidays(year) {
    const holidays = new Set();
    const addHoliday = function(date) {
      holidays.add(formatDateKey(date));
    };

    const newYearsDay = new Date(year, 0, 1);
    addHoliday(newYearsDay);
    if (newYearsDay.getDay() === 6) addHoliday(new Date(year, 0, 3));
    if (newYearsDay.getDay() === 0) addHoliday(new Date(year, 0, 2));

    const australiaDay = new Date(year, 0, 26);
    addHoliday(australiaDay);
    if (australiaDay.getDay() === 6) addHoliday(new Date(year, 0, 28));
    if (australiaDay.getDay() === 0) addHoliday(new Date(year, 0, 27));

    const easterSunday = getEasterSunday(year);
    addHoliday(addDays(easterSunday, -2));
    addHoliday(addDays(easterSunday, -1));
    addHoliday(easterSunday);
    addHoliday(addDays(easterSunday, 1));

    const anzacDay = new Date(year, 3, 25);
    addHoliday(anzacDay);
    if (anzacDay.getDay() === 0) addHoliday(new Date(year, 3, 26));

    addHoliday(nthWeekdayOfMonth(year, 5, 1, 1));
    addHoliday(getBrisbaneShowDay(year));
    addHoliday(nthWeekdayOfMonth(year, 10, 1, 1));

    const christmasDay = new Date(year, 11, 25);
    const boxingDay = new Date(year, 11, 26);
    addHoliday(christmasDay);
    addHoliday(boxingDay);

    if (christmasDay.getDay() === 6 || christmasDay.getDay() === 0) {
      addHoliday(new Date(year, 11, 27));
    }
    if (boxingDay.getDay() === 6 || boxingDay.getDay() === 0) {
      addHoliday(new Date(year, 11, 28));
    }

    /* Queensland also has a part-day public holiday on Christmas Eve from 6pm-midnight.
       It does not affect this widget because your shipping cutoff is earlier at 2:30pm Brisbane time. */
    return holidays;
  }

  function isPublicHoliday(date) {
    const year = date.getFullYear();
    if (!holidayCache.has(year)) {
      holidayCache.set(year, buildQueenslandPublicHolidays(year));
    }
    return holidayCache.get(year).has(formatDateKey(date));
  }

  function isDispatchBusinessDay(date) {
    const day = date.getDay();
    return day !== 0 && day !== 6 && !isPublicHoliday(date);
  }

  function getNextDispatchDate(today, isPastCutoff) {
    let candidate = new Date(today);

    if (isPastCutoff || !isDispatchBusinessDay(candidate)) {
      candidate = addDays(candidate, 1);
    }

    while (!isDispatchBusinessDay(candidate)) {
      candidate = addDays(candidate, 1);
    }

    return candidate;
  }

  function getDispatchTitle(today, nextDispatch, isHolidayToday) {
    if (isHolidayToday) return "Public Holiday";
    if (sameDate(nextDispatch, today)) return "Ships Today";
    if (sameDate(nextDispatch, addDays(today, 1))) return "Ships Tomorrow";
    return "Ships " + weekdayNames[nextDispatch.getDay()];
  }

  function getDispatchSub(today, nextDispatch, isHolidayToday) {
    if (isHolidayToday) {
      return "Shipping resumes " + weekdayNames[nextDispatch.getDay()];
    }

    if (sameDate(nextDispatch, today)) {
      return "Order within the next";
    }

    if (nextDispatch.getDay() === 1) {
      return "Secure your spot for Monday's first dispatch";
    }

    return "Order now for priority dispatch";
  }

  function update() {
    const brisbaneParts = getBrisbaneParts(getReferenceDate());
    const today = atStartOfDay(toLocalDate(brisbaneParts));
    const isHolidayToday = isPublicHoliday(today);
    const isPastCutoff =
      brisbaneParts.hour > cutoffHour ||
      (brisbaneParts.hour === cutoffHour && brisbaneParts.minute >= cutoffMinute);

    const canShipToday = isDispatchBusinessDay(today) && !isPastCutoff;
    const nextDispatch = canShipToday ? today : getNextDispatchDate(today, isPastCutoff);

    titleEl.textContent = getDispatchTitle(today, nextDispatch, isHolidayToday);
    subEl.textContent = getDispatchSub(today, nextDispatch, isHolidayToday);

    if (!canShipToday) {
      timerEl.innerHTML = "";
      return;
    }

    const cutoffDate = toLocalDate({
      year: brisbaneParts.year,
      month: brisbaneParts.month,
      day: brisbaneParts.day,
      hour: cutoffHour,
      minute: cutoffMinute,
      second: 0
    });

    const currentDate = toLocalDate(brisbaneParts);
    const diff = Math.max(0, cutoffDate - currentDate);
    const hh = Math.floor(diff / 36e5);
    const mm = Math.floor((diff % 36e5) / 6e4);
    const ss = Math.floor((diff % 6e4) / 1e3);

    const timeParts = [];
    if (hh > 0) timeParts.push(hh + "h");
    timeParts.push(mm + "m");
    timeParts.push(ss + "s");

    timerEl.innerHTML = "<strong>" + timeParts.join(" ") + "</strong>";
  }

  update();
  setInterval(update, 1000);
})();
</script>

{% assign paired_products = product.metafields.custom.pairs_well_with.value %}

{% if paired_products != blank %}
<div class="pairs-row-wrap">
  <div class="pairs-row">
    <div class="pairs-row-label">
      Recommended With
    </div>

    <div class="pairs-row-content">
      {% for paired_product in paired_products limit: 2 %}
        <div class="pairs-inline-item">
          <a href="{{ paired_product.url }}" class="pairs-inline-image">
            <img
              src="{{ paired_product.featured_image | image_url: width: 160 }}"
              alt="{{ paired_product.title | escape }}"
              loading="lazy"
              width="56"
              height="56"
            >
          </a>

          <div class="pairs-inline-text">
            <a href="{{ paired_product.url }}" class="pairs-inline-title">
              {{ paired_product.title }}
            </a>

            <div class="pairs-inline-price">
              {{ paired_product.price | money }}
            </div>

            <form method="post" action="/cart/add" class="pairs-inline-form">
              <input type="hidden" name="id" value="{{ paired_product.selected_or_first_available_variant.id }}">
              <button type="submit" class="pairs-inline-link">
                Add to cart
              </button>
            </form>
          </div>
        </div>
      {% endfor %}
    </div>
  </div>
</div>

<style>
.pairs-row-wrap{
  border-top: 1px solid rgba(0,0,0,0.08);
  margin-top: 22px;
  padding-top: 22px;
}

.pairs-row{
  display: grid;
  grid-template-columns: 80px minmax(0,1fr);
  column-gap: 18px;
  align-items: start;
}

.pairs-row-label{
  font-size: 13px;
  line-height: 1.4;
  font-weight: 600;
  color: #867e73;
  padding-top: 2px;
}

.pairs-row-content{
  display: flex;
  flex-direction: column;
  gap: 16px;
  min-width: 0;
}

.pairs-inline-item{
  display: flex;
  align-items: flex-start;
  gap: 12px;
  min-width: 0;
}

.pairs-inline-image{
  flex: 0 0 56px;
  width: 56px;
  text-decoration: none;
}

.pairs-inline-image img{
  display: block;
  width: 56px;
  height: 56px;
  object-fit: cover;
  border-radius: 8px;
  background: #f5f3f0;
}

.pairs-inline-text{
  min-width: 0;
  flex: 1;
}

.pairs-inline-title{
  display: block;
  margin: 0 0 2px 0;
  color: #222222;
  text-decoration: none;
  font-size: 14px;
  line-height: 1.45;
  font-weight: 600;
}

.pairs-inline-title:hover{
  text-decoration: underline;
}

.pairs-inline-price{
  margin-bottom: 2px;
  color: #867e73;
  font-size: 14px;
  line-height: 1.45;
  font-weight: 400;
}

.pairs-inline-form{
  margin: 0;
}

.pairs-inline-link{
  padding: 0;
  border: 0;
  background: none;
  font: inherit;
  color: #867e73;
  font-size: 14px;
  line-height: 1.45;
  font-weight: 400;
  text-decoration: underline;
  text-underline-offset: 2px;
  cursor: pointer;
}

.pairs-inline-link:hover{
  color: #222222;
}

@media screen and (max-width: 749px){
  .pairs-row{
    grid-template-columns: 1fr;
    row-gap: 10px;
  }

  .pairs-row-label{
    padding-top: 0;
  }
}
</style>
{% endif %}
